import{_ as r,o as a,c as t,ag as i}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"Factures","description":"","frontmatter":{},"headers":[],"relativePath":"fr/features/invoices.md","filePath":"fr/features/invoices.md"}'),l={name:"fr/features/invoices.md"};function n(o,e,s,u,c,d){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="factures" tabindex="-1">Factures <a class="header-anchor" href="#factures" aria-label="Permalink to &quot;Factures&quot;">​</a></h1><p>Les factures sont au coeur de MyCompanyDesk. Creez des factures professionnelles, envoyez-les a vos clients avec des liens de paiement et suivez les paiements jusqu&#39;a leur reception.</p><h2 id="vue-d-ensemble" tabindex="-1">Vue d&#39;ensemble <a class="header-anchor" href="#vue-d-ensemble" aria-label="Permalink to &quot;Vue d&#39;ensemble&quot;">​</a></h2><p>La page des factures affiche toutes vos factures avec des fonctionnalites de filtrage et de recherche. Utilisez les onglets de statut pour consulter rapidement :</p><ul><li><strong>Toutes</strong> -- Toutes les factures</li><li><strong>Brouillon</strong> -- Creees mais non envoyees</li><li><strong>Envoyees</strong> -- Transmises aux clients</li><li><strong>En retard</strong> -- Date d&#39;echeance depassee, impayees</li><li><strong>Payees</strong> -- Paiement recu</li><li><strong>Annulees</strong> -- Factures annulees</li></ul><h2 id="creer-une-facture" tabindex="-1">Creer une facture <a class="header-anchor" href="#creer-une-facture" aria-label="Permalink to &quot;Creer une facture&quot;">​</a></h2><h3 id="formulaire-complet" tabindex="-1">Formulaire complet <a class="header-anchor" href="#formulaire-complet" aria-label="Permalink to &quot;Formulaire complet&quot;">​</a></h3><ol><li>Allez dans <strong>Factures &gt; Nouvelle facture</strong></li><li>Selectionnez ou creez un <strong>client</strong></li><li>Ajoutez des <strong>lignes de facturation</strong> avec description, quantite, prix unitaire et taux de TVA</li><li>Definissez la <strong>date de facture</strong> et la <strong>date d&#39;echeance</strong></li><li>Ajoutez des <strong>notes</strong> ou <strong>remarques internes</strong> optionnelles</li><li>Cliquez sur <strong>Enregistrer</strong> pour creer un brouillon</li></ol><h3 id="ajout-rapide" tabindex="-1">Ajout rapide <a class="header-anchor" href="#ajout-rapide" aria-label="Permalink to &quot;Ajout rapide&quot;">​</a></h3><p>Pour une creation plus rapide :</p><ol><li>Cliquez sur le bouton d&#39;ajout rapide dans la liste des factures</li><li>Selectionnez un client</li><li>Ajoutez des elements ou choisissez un modele</li><li>Enregistrez (et envoyez immediatement si vous le souhaitez)</li></ol><h3 id="a-partir-d-un-modele" tabindex="-1">A partir d&#39;un modele <a class="header-anchor" href="#a-partir-d-un-modele" aria-label="Permalink to &quot;A partir d&#39;un modele&quot;">​</a></h3><ol><li>Lors de la creation d&#39;une nouvelle facture, cliquez sur <strong>Utiliser un modele</strong></li><li>Selectionnez un modele enregistre</li><li>Toutes les lignes de facturation sont pre-remplies -- ajustez selon vos besoins</li><li>Enregistrez et envoyez</li></ol><h2 id="details-de-la-facture" tabindex="-1">Details de la facture <a class="header-anchor" href="#details-de-la-facture" aria-label="Permalink to &quot;Details de la facture&quot;">​</a></h2><p>Chaque facture dispose d&#39;une page de detail affichant :</p><ul><li>Informations du client</li><li>Lignes de facturation avec sous-totaux</li><li>Ventilation de la TVA</li><li>Montant total</li><li>Statut et historique</li><li>Lien de paiement (si envoye)</li></ul><h2 id="actions" tabindex="-1">Actions <a class="header-anchor" href="#actions" aria-label="Permalink to &quot;Actions&quot;">​</a></h2><h3 id="envoyer" tabindex="-1">Envoyer <a class="header-anchor" href="#envoyer" aria-label="Permalink to &quot;Envoyer&quot;">​</a></h3><p>Envoyez la facture a votre client par e-mail. L&#39;e-mail comprend :</p><ul><li>Un message personnalisable (base sur votre modele d&#39;e-mail)</li><li>La facture PDF en piece jointe</li><li>Un lien de paiement pour le paiement en ligne</li></ul><h3 id="telecharger-le-pdf" tabindex="-1">Telecharger le PDF <a class="header-anchor" href="#telecharger-le-pdf" aria-label="Permalink to &quot;Telecharger le PDF&quot;">​</a></h3><p>Telechargez la facture sous forme de document PDF mis en forme professionnellement. Le PDF inclut le logo de votre entreprise, les couleurs de votre marque et tous les details de la facture.</p><h3 id="marquer-comme-payee" tabindex="-1">Marquer comme payee <a class="header-anchor" href="#marquer-comme-payee" aria-label="Permalink to &quot;Marquer comme payee&quot;">​</a></h3><p>Confirmez manuellement le paiement lorsqu&#39;un client paie par virement bancaire ou autre methode hors ligne.</p><h3 id="annuler" tabindex="-1">Annuler <a class="header-anchor" href="#annuler" aria-label="Permalink to &quot;Annuler&quot;">​</a></h3><p>Annulez une facture qui ne doit plus etre payee. Les factures annulees restent dans vos archives a des fins d&#39;audit.</p><h3 id="dupliquer" tabindex="-1">Dupliquer <a class="header-anchor" href="#dupliquer" aria-label="Permalink to &quot;Dupliquer&quot;">​</a></h3><p>Creez une copie d&#39;une facture existante -- utile pour la facturation recurrente au meme client.</p><h3 id="envoyer-un-rappel" tabindex="-1">Envoyer un rappel <a class="header-anchor" href="#envoyer-un-rappel" aria-label="Permalink to &quot;Envoyer un rappel&quot;">​</a></h3><p>Envoyez un rappel de paiement pour les factures en retard.</p><h2 id="actions-groupees" tabindex="-1">Actions groupees <a class="header-anchor" href="#actions-groupees" aria-label="Permalink to &quot;Actions groupees&quot;">​</a></h2><p>Selectionnez plusieurs factures dans la liste pour effectuer des actions groupees :</p><ul><li><strong>Envoyer</strong> -- Envoyez plusieurs factures brouillon en une fois</li><li><strong>Marquer comme payees</strong> -- Enregistrez le paiement de plusieurs factures</li><li><strong>Archiver</strong> -- Deplacez les factures vers les archives</li><li><strong>Supprimer</strong> -- Supprimez definitivement des factures</li></ul><h2 id="liens-de-paiement" tabindex="-1">Liens de paiement <a class="header-anchor" href="#liens-de-paiement" aria-label="Permalink to &quot;Liens de paiement&quot;">​</a></h2><p>Lorsque vous envoyez une facture, un lien de paiement unique est genere. Votre client peut :</p><ol><li>Cliquer sur le lien dans l&#39;e-mail</li><li>Consulter la facture dans le <strong>portail client</strong></li><li>Payer directement en ligne</li></ol><p>Le paiement est automatiquement enregistre et le statut de la facture passe a <strong>Payee</strong>.</p><h2 id="types-de-documents" tabindex="-1">Types de documents <a class="header-anchor" href="#types-de-documents" aria-label="Permalink to &quot;Types de documents&quot;">​</a></h2><p>Le module de facturation prend en charge plusieurs types de documents :</p><ul><li><strong>Facture</strong> -- Document de facturation standard</li><li><strong>Avoir</strong> -- Ajustement pour remboursements ou corrections</li><li><strong>Rappel</strong> -- Rappel de paiement pour les factures en retard</li></ul><h2 id="filtrage-et-recherche" tabindex="-1">Filtrage et recherche <a class="header-anchor" href="#filtrage-et-recherche" aria-label="Permalink to &quot;Filtrage et recherche&quot;">​</a></h2><p>Utilisez la barre de filtre pour affiner vos factures :</p><ul><li><strong>Statut</strong> -- Brouillon, Envoyee, En retard, Payee, Annulee</li><li><strong>Client</strong> -- Filtrer par client specifique</li><li><strong>Projet</strong> -- Filtrer par projet lie</li><li><strong>Plage de dates</strong> -- Filtrer par date de facture ou d&#39;echeance</li><li><strong>Recherche</strong> -- Rechercher par numero de facture, nom de client ou description</li></ul><h2 id="export" tabindex="-1">Export <a class="header-anchor" href="#export" aria-label="Permalink to &quot;Export&quot;">​</a></h2><p>Exportez vos factures au format CSV pour les utiliser dans Excel, Google Sheets ou votre logiciel de comptabilite.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>L&#39;export CSV necessite le plan <strong>Pro</strong> ou superieur.</p></div><h2 id="conseils" tabindex="-1">Conseils <a class="header-anchor" href="#conseils" aria-label="Permalink to &quot;Conseils&quot;">​</a></h2><ul><li>Configurez vos <a href="/fr/settings/email">modeles d&#39;e-mail</a> avant d&#39;envoyer votre premiere facture</li><li>Utilisez les <a href="/fr/features/recurring-invoices">factures recurrentes</a> pour la facturation reguliere</li><li>Consultez la page des <a href="/fr/features/reports">rapports</a> pour des analyses de revenus</li><li>Activez les <a href="/fr/advanced/ai-features">suggestions IA</a> pour des ameliorations intelligentes des descriptions</li></ul>',48)])])}const m=r(l,[["render",n]]);export{h as __pageData,m as default};
